// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <string.h>
#define MOD 23102009

int dpLen[1002][1002];
int cnt[1002][1002];

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[1002], t[1002];
        scanf("%s %s", s, t);
        int n = strlen(s);
        int m = strlen(t);
        // base cases
        for (int i = 0; i <= n; ++i) {
            dpLen[i][m] = 0;
            cnt[i][m] = 1;
        }
        for (int j = 0; j <= m; ++j) {
            dpLen[n][j] = 0;
            cnt[n][j] = 1;
        }
        // fill DP bottom‑up
        for (int i = n - 1; i >= 0; --i) {
            for (int j = m - 1; j >= 0; --j) {
                if (s[i] == t[j]) {
                    dpLen[i][j] = 1 + dpLen[i + 1][j + 1];
                    cnt[i][j] = cnt[i + 1][j + 1];
                } else {
                    if (dpLen[i + 1][j] > dpLen[i][j + 1]) {
                        dpLen[i][j] = dpLen[i + 1][j];
                        cnt[i][j] = cnt[i + 1][j];
                    } else if (dpLen[i + 1][j] < dpLen[i][j + 1]) {
                        dpLen[i][j] = dpLen[i][j + 1];
                        cnt[i][j] = cnt[i][j + 1];
                    } else { // equal length
                        dpLen[i][j] = dpLen[i + 1][j];
                        int val = cnt[i + 1][j] + cnt[i][j + 1];
                        if (val >= MOD) val -= MOD;
                        if (dpLen[i + 1][j + 1] == dpLen[i][j]) {
                            val -= cnt[i + 1][j + 1];
                            if (val < 0) val += MOD;
                        }
                        cnt[i][j] = val;
                    }
                }
            }
        }
        printf("%d %d\n", dpLen[0][0], cnt[0][0] % MOD);
    }
    return 0;
}

